import { useCart } from '../contexts/CartContext';
import { Minus, Plus, Trash2, ShoppingBag, ArrowLeft } from 'lucide-react';

interface CartProps {
  onNavigate?: (page: string) => void;
}

export function Cart({ onNavigate }: CartProps) {
  const { cartItems, cartTotal, loading, updateCartItem, removeFromCart } = useCart();

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-neutral-50">
        <div className="text-center">
          <div className="w-12 h-12 border-4 border-brand-primary border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-neutral-600 animate-pulse">Loading your cart...</p>
        </div>
      </div>
    );
  }

  if (cartItems.length === 0) {
    return (
      <div className="min-h-screen bg-neutral-50 flex items-center justify-center">
        <div className="text-center">
          <button
            onClick={() => onNavigate?.('home')}
            className="mb-6 flex items-center text-neutral-600 hover:text-brand-primary transition-colors group"
          >
            <ArrowLeft className="h-4 w-4 mr-2 group-hover:-translate-x-1 transition-transform" />
            Back to Home
          </button>
          <div className="w-32 h-32 bg-neutral-100 rounded-full flex items-center justify-center mx-auto mb-6">
            <ShoppingBag className="h-16 w-16 text-neutral-300" />
          </div>
          <h2 className="text-3xl font-bold text-neutral-900 mb-4">Your cart is empty</h2>
          <p className="text-neutral-600 mb-8 text-lg">Add some fresh products to get started</p>
          <button
            onClick={() => onNavigate?.('products')}
            className="btn btn-primary px-8 py-4 text-lg font-semibold rounded-xl shadow-lg hover:shadow-xl transform hover:-translate-y-0.5 transition-all duration-200"
          >
            Browse Products
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-neutral-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Back to Home */}
        <button
          onClick={() => onNavigate?.('home')}
          className="mb-6 flex items-center text-neutral-600 hover:text-brand-primary transition-colors group"
        >
          <ArrowLeft className="h-4 w-4 mr-2 group-hover:-translate-x-1 transition-transform" />
          Back to Home
        </button>

        <h1 className="text-4xl font-bold text-neutral-900 mb-8 flex items-center gap-3">
          <div className="w-12 h-12 bg-brand-primary/10 rounded-lg flex items-center justify-center">
            <ShoppingBag className="h-6 w-6 text-brand-primary" />
          </div>
          Shopping Cart
        </h1>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2">
            <div className="card bg-white rounded-2xl shadow-lg overflow-hidden border border-neutral-200">
              {cartItems.map((item) => {
                const price = item.product.discount_price || item.product.price;
                const subtotal = price * item.quantity;

                return (
                  <div key={item.id} className="flex items-center gap-4 p-6 border-b border-neutral-100 last:border-b-0 hover:bg-neutral-50 transition-colors">
                    <div className="relative">
                      <img
                        src={item.product.image_url || 'https://images.pexels.com/photos/1435904/pexels-photo-1435904.jpeg?auto=compress&cs=tinysrgb&w=200'}
                        alt={item.product.name}
                        className="w-20 h-20 object-cover rounded-xl"
                        loading="lazy"
                      />
                      {item.product.discount_price && (
                        <div className="badge badge-error absolute -top-2 -right-2">
                          {Math.round(((item.product.price - price) / item.product.price) * 100)}% OFF
                        </div>
                      )}
                    </div>
                    
                    <div className="flex-1">
                      <div className="flex justify-between items-start mb-2">
                        <div>
                          <h3 className="font-semibold text-neutral-900 text-lg">{item.product.name}</h3>
                          <p className="text-sm text-neutral-500">{item.product.unit}</p>
                        </div>
                        <button
                          onClick={() => removeFromCart(item.id)}
                          className="text-error hover:text-error/80 transition-colors p-2 rounded-lg hover:bg-error/10"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                      
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <button
                            onClick={() => updateCartItem(item.id, Math.max(1, item.quantity - 1))}
                            className="btn btn-secondary p-2 rounded-lg"
                            disabled={item.quantity <= 1}
                          >
                            <Minus className="h-4 w-4" />
                          </button>
                          <span className="font-semibold text-lg w-12 text-center">{item.quantity}</span>
                          <button
                            onClick={() => updateCartItem(item.id, item.quantity + 1)}
                            className="btn btn-secondary p-2 rounded-lg"
                          >
                            <Plus className="h-4 w-4" />
                          </button>
                        </div>
                        
                        <div className="text-right">
                          <div className="text-sm text-neutral-500">₹{price.toFixed(2)} each</div>
                          <div className="text-xl font-bold text-neutral-900">₹{subtotal.toFixed(2)}</div>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
          
          <div className="lg:col-span-1">
            <div className="card bg-white rounded-2xl shadow-lg p-6 border border-neutral-200 sticky top-4">
              <h2 className="text-xl font-bold text-neutral-900 mb-6">Order Summary</h2>
              
              <div className="space-y-4 mb-6">
                <div className="flex justify-between text-neutral-600">
                  <span>Subtotal</span>
                  <span>₹{cartTotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-neutral-600">
                  <span>Delivery</span>
                  <span className="text-success">FREE</span>
                </div>
                <div className="border-t border-neutral-200 pt-4">
                  <div className="flex justify-between text-xl font-bold text-neutral-900">
                    <span>Total</span>
                    <span>₹{cartTotal.toFixed(2)}</span>
                  </div>
                </div>
              </div>
              
              <div className="space-y-3">
                <button
                  onClick={() => onNavigate?.('checkout')}
                  className="btn btn-primary w-full py-4 text-lg font-semibold rounded-xl shadow-lg hover:shadow-xl transform hover:-translate-y-0.5 transition-all duration-200"
                >
                  Proceed to Checkout
                </button>
                <button
                  onClick={() => onNavigate?.('products')}
                  className="btn btn-secondary w-full py-3 text-base font-medium rounded-xl"
                >
                  Continue Shopping
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
