import { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { User, Mail, Phone, MapPin, Save, ArrowLeft } from 'lucide-react';

interface ProfileProps {
  onNavigate?: (page: string) => void;
}

export function Profile({ onNavigate }: ProfileProps) {
  const { profile, updateProfile } = useAuth();
  const [formData, setFormData] = useState({
    full_name: profile?.full_name || '',
    phone: profile?.phone || '',
    address: profile?.address || '',
  });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });
  const [focusedField, setFocusedField] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData(prev => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage({ type: '', text: '' });

    try {
      const { error } = await updateProfile(formData);

      if (error) {
        setMessage({ type: 'error', text: error.message });
      } else {
        setMessage({ type: 'success', text: 'Profile updated successfully!' });
      }
    } catch (err) {
      setMessage({ type: 'error', text: 'An unexpected error occurred' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-neutral-50 py-8">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Back to Home */}
        <button
          onClick={() => onNavigate?.('home')}
          className="mb-6 flex items-center text-neutral-600 hover:text-brand-primary transition-colors group"
        >
          <ArrowLeft className="h-4 w-4 mr-2 group-hover:-translate-x-1 transition-transform" />
          Back to Home
        </button>

        <div className="card bg-white rounded-2xl shadow-lg overflow-hidden border border-neutral-200">
          {/* Professional Header */}
          <div className="bg-gradient-to-r from-brand-primary to-brand-secondary p-8 relative overflow-hidden">
            {/* Background Pattern */}
            <div className="absolute inset-0 opacity-10">
              <div className="absolute top-0 left-0 w-32 h-32 bg-white rounded-full blur-2xl"></div>
              <div className="absolute bottom-0 right-0 w-32 h-32 bg-white rounded-full blur-2xl"></div>
            </div>
            
            <div className="relative z-10 flex items-center gap-6">
              <div className="w-24 h-24 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center border-2 border-white/30">
                <User className="h-12 w-12 text-white" />
              </div>
              <div className="text-white">
                <h1 className="text-3xl font-bold mb-1">{profile?.full_name || 'User'}</h1>
                <p className="text-white/90 flex items-center gap-2">
                  <Mail className="h-4 w-4" />
                  {profile?.email}
                </p>
              </div>
            </div>
          </div>

          <div className="p-8">
            <h2 className="text-2xl font-bold text-neutral-900 mb-8 flex items-center gap-3">
              <div className="w-8 h-8 bg-brand-primary/10 rounded-lg flex items-center justify-center">
                <User className="h-4 w-4 text-brand-primary" />
              </div>
              Profile Information
            </h2>

            {message.text && (
              <div className={`alert mb-6 flex items-start gap-3 ${
                message.type === 'success' 
                  ? 'alert-success bg-success/10 border-success/20 text-success' 
                  : 'alert-error bg-error/10 border-error/20 text-error'
              }`}>
                <div className={`w-5 h-5 rounded-full flex items-center justify-center flex-shrink-0 mt-0.5 ${
                  message.type === 'success' ? 'bg-success' : 'bg-error'
                }`}>
                  {message.type === 'success' ? (
                    <span className="text-white text-xs font-bold">✓</span>
                  ) : (
                    <span className="text-white text-xs font-bold">!</span>
                  )}
                </div>
                <div>
                  <p className="font-medium">{message.type === 'success' ? 'Success' : 'Error'}</p>
                  <p className="text-sm mt-1 opacity-80">{message.text}</p>
                </div>
              </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-8">
              {/* Email Field */}
              <div className="space-y-3">
                <label htmlFor="email" className="block text-sm font-semibold text-neutral-800 flex items-center gap-2">
                  <Mail className="h-4 w-4 text-neutral-600" />
                  Email Address
                </label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <Mail className={`h-5 w-5 transition-colors ${focusedField === 'email' ? 'text-brand-primary' : 'text-neutral-400'}`} />
                  </div>
                  <input
                    id="email"
                    type="email"
                    value={profile?.email}
                    disabled
                    className="input-field pl-12 pr-4 py-4 w-full border border-neutral-200 rounded-xl bg-neutral-50 text-neutral-500 cursor-not-allowed"
                  />
                </div>
                <p className="text-sm text-neutral-500 flex items-center gap-1">
                  <span>ℹ️</span>
                  <span>Email cannot be changed</span>
                </p>
              </div>

              {/* Full Name Field */}
              <div className="space-y-3">
                <label htmlFor="full_name" className="block text-sm font-semibold text-neutral-800 flex items-center gap-2">
                  <User className="h-4 w-4 text-neutral-600" />
                  Full Name
                </label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <User className={`h-5 w-5 transition-colors ${focusedField === 'full_name' ? 'text-brand-primary' : 'text-neutral-400'}`} />
                  </div>
                  <input
                    id="full_name"
                    name="full_name"
                    type="text"
                    value={formData.full_name}
                    onChange={handleChange}
                    onFocus={() => setFocusedField('full_name')}
                    onBlur={() => setFocusedField('')}
                    required
                    className="input-field pl-12 pr-4 py-4 w-full border border-neutral-200 rounded-xl focus:ring-2 focus:ring-brand-primary/20 focus:border-brand-primary transition-all duration-200 bg-white hover:bg-neutral-50"
                    placeholder="Enter your full name"
                  />
                </div>
              </div>

              {/* Phone Field */}
              <div className="space-y-3">
                <label htmlFor="phone" className="block text-sm font-semibold text-neutral-800 flex items-center gap-2">
                  <Phone className="h-4 w-4 text-neutral-600" />
                  Phone Number
                </label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <Phone className={`h-5 w-5 transition-colors ${focusedField === 'phone' ? 'text-brand-primary' : 'text-neutral-400'}`} />
                  </div>
                  <input
                    id="phone"
                    name="phone"
                    type="tel"
                    value={formData.phone}
                    onChange={handleChange}
                    onFocus={() => setFocusedField('phone')}
                    onBlur={() => setFocusedField('')}
                    className="input-field pl-12 pr-4 py-4 w-full border border-neutral-200 rounded-xl focus:ring-2 focus:ring-brand-primary/20 focus:border-brand-primary transition-all duration-200 bg-white hover:bg-neutral-50"
                    placeholder="+91 1234567890"
                  />
                </div>
              </div>

              {/* Address Field */}
              <div className="space-y-3">
                <label htmlFor="address" className="block text-sm font-semibold text-neutral-800 flex items-center gap-2">
                  <MapPin className="h-4 w-4 text-neutral-600" />
                  Delivery Address
                </label>
                <div className="relative">
                  <div className="absolute top-4 left-0 pl-4 flex items-start pointer-events-none">
                    <MapPin className={`h-5 w-5 transition-colors ${focusedField === 'address' ? 'text-brand-primary' : 'text-neutral-400'}`} />
                  </div>
                  <textarea
                    id="address"
                    name="address"
                    value={formData.address}
                    onChange={handleChange}
                    onFocus={() => setFocusedField('address')}
                    onBlur={() => setFocusedField('')}
                    rows={4}
                    className="input-field pl-12 pr-4 py-4 w-full border border-neutral-200 rounded-xl focus:ring-2 focus:ring-brand-primary/20 focus:border-brand-primary transition-all duration-200 bg-white hover:bg-neutral-50 resize-none"
                    placeholder="Enter your complete delivery address"
                  />
                </div>
              </div>

              {/* Submit Button */}
              <button
                type="submit"
                disabled={loading}
                className="btn btn-primary w-full py-4 text-base font-semibold rounded-xl shadow-lg hover:shadow-xl transform hover:-translate-y-0.5 transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none flex items-center justify-center gap-3"
              >
                <Save className="h-5 w-5" />
                {loading ? (
                  <span className="flex items-center gap-2">
                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                    Saving Changes...
                  </span>
                ) : (
                  'Save Changes'
                )}
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}
